// 5️⃣ Logout function (optional)
export const logoutUser = () => {
  localStorage.removeItem("nfxtoken");
  localStorage.removeItem("userEmail");
};

// 6️⃣ Example of a protected API call
export const getDashboardData = async () => {
  const response = await api.get("/dashboard"); // token automatically attached
  return response.data;
};

export default api;
